import { experiments } from "./experiments";

export type VisualizationStatus = "custom" | "specific-shared-engine" | "generic-fallback" | "pending-custom";
export type VisualizationPane = "twoD" | "threeD";

export interface VisualizationPaneSpec {
  status: VisualizationStatus;
  engine?: string;
  requiredVisualElements: string[];
  requiredMeasurements: string[];
  requiredGraphs?: string[];
  requiredControls?: string[];
  apparatus?: string[];
  studentLearningGoal: string;
  scientificAssumptions?: string[];
  limitationCopy?: string;
  fullscreenReady?: boolean;
  keyboardNavigable?: boolean;
  reducedMotionReady?: boolean;
  labelVisibility?: "clear" | "needs-review" | "pending";
}

export interface ExperimentVisualizationSpec {
  experimentId: string;
  domain: string;
  visualIdentity: string;
  primaryConcept: string;
  twoD: VisualizationPaneSpec;
  threeD: VisualizationPaneSpec;
  allowSharedEngineOnlyIf?: string[];
  mustNotUseGenericFallback: boolean;
  phaseAssigned?: number;
  teacherCheck: string;
  studentCheck: string;
  uiCheck: string;
}

function pane(status: VisualizationStatus, engine: string, requiredVisualElements: string[], requiredMeasurements: string[], studentLearningGoal: string, options: Partial<VisualizationPaneSpec> = {}): VisualizationPaneSpec {
  return { status, engine, requiredVisualElements, requiredMeasurements, studentLearningGoal, fullscreenReady: status === "custom" || status === "specific-shared-engine", keyboardNavigable: true, reducedMotionReady: status === "pending-custom", labelVisibility: status === "pending-custom" ? "pending" : "clear", ...options };
}

