export const experimentVisualizationSpecById: Record<string, ExperimentVisualizationSpec> = Object.fromEntries(experimentVisualizationSpecs.map((spec) => [spec.experimentId, spec]));

export function getExperimentVisualizationSpec(experimentId: string) { return experimentVisualizationSpecById[experimentId]; }
export function getVisualizationStatus(experimentId: string, paneName: VisualizationPane): VisualizationStatus | undefined { return getExperimentVisualizationSpec(experimentId)?.[paneName].status; }
export function isPanePending(spec: VisualizationPaneSpec) { return spec.status === "generic-fallback" || spec.status === "pending-custom"; }
export function requiresCustom2D(experimentId: string) { const spec = getExperimentVisualizationSpec(experimentId); return spec ? isPanePending(spec.twoD) : true; }
export function requiresCustom3D(experimentId: string) { const spec = getExperimentVisualizationSpec(experimentId); return spec ? isPanePending(spec.threeD) : true; }

export function getPendingVisualizationSummary(experimentId: string) {
  const spec = getExperimentVisualizationSpec(experimentId);
  if (!spec) return undefined;
  const pending: VisualizationPane[] = [];
  if (isPanePending(spec.twoD)) pending.push("twoD");
  if (isPanePending(spec.threeD)) pending.push("threeD");
  return { experimentId, pending, phaseAssigned: spec.phaseAssigned, visualIdentity: spec.visualIdentity, studentLearningGoal: spec.primaryConcept };
}

export function assertVisualizationSpecCoverage(experimentList = experiments, specs = experimentVisualizationSpecs) {
  const experimentIds = new Set(experimentList.map((experiment) => experiment.id));
  const specIds = new Set(specs.map((spec) => spec.experimentId));
  const missingSpecs = [...experimentIds].filter((id) => !specIds.has(id));
  const unknownSpecs = [...specIds].filter((id) => !experimentIds.has(id));
  const duplicateSpecs = specs.map((spec) => spec.experimentId).filter((id, index, ids) => ids.indexOf(id) !== index);
  const incompleteSpecs = specs.filter((spec) => !spec.twoD?.status || !spec.threeD?.status).map((spec) => spec.experimentId);
  const unphasedPending = specs.filter((spec) => (isPanePending(spec.twoD) || isPanePending(spec.threeD)) && !spec.phaseAssigned).map((spec) => spec.experimentId);
  const silentFallbacks = specs.filter((spec) => !spec.mustNotUseGenericFallback).map((spec) => spec.experimentId);
  return { ok: missingSpecs.length === 0 && unknownSpecs.length === 0 && duplicateSpecs.length === 0 && incompleteSpecs.length === 0 && unphasedPending.length === 0 && silentFallbacks.length === 0, missingSpecs, unknownSpecs, duplicateSpecs, incompleteSpecs, unphasedPending, silentFallbacks };
}